from mcp.server.fastmcp import FastMCP

mcp = FastMCP("lab_marker_server")

@mcp.tool()
def lab_marker() -> dict[str, str]:
    """Return the controlled marker for the Claude Code MCP benign experiment."""
    return {"marker": "CLAUDE_MCP_MARKER_R01"}

if __name__ == "__main__":
    mcp.run(transport="stdio")
